import{_ as t,o as a,c as o,ag as s}from"./chunks/framework.1N8rnUr9.js";const u=JSON.parse('{"title":"Visual Placement","description":"","frontmatter":{},"headers":[],"relativePath":"features/placement.md","filePath":"features/placement.md","lastUpdated":1775898496000}'),i={name:"features/placement.md"};function r(n,e,l,d,c,h){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="visual-placement" tabindex="-1">Visual Placement <a class="header-anchor" href="#visual-placement" aria-label="Permalink to &quot;Visual Placement&quot;">​</a></h1><p>TubeBay allows you to choose exactly where the video player should appear on your product pages. This is managed via hooks and can be configured globally or overridden for specific needs.</p><h2 id="global-placement-settings" tabindex="-1">Global Placement Settings <a class="header-anchor" href="#global-placement-settings" aria-label="Permalink to &quot;Global Placement Settings&quot;">​</a></h2><p>In <strong>Settings &gt; Video Player</strong>, you can choose from several predefined locations:</p><table tabindex="0"><thead><tr><th>Location</th><th>Technical Hook</th><th>Description</th></tr></thead><tbody><tr><td><strong>Above Product Gallery</strong></td><td><code>woocommerce_before_single_product_summary</code> (priority 5)</td><td>Places the video at the very top of the product image area.</td></tr><tr><td><strong>Below Product Gallery</strong></td><td><code>woocommerce_product_thumbnails</code> (priority 20)</td><td>Displays the video underneath the main product images.</td></tr><tr><td><strong>After Product Summary</strong></td><td><code>woocommerce_after_single_product_summary</code></td><td>Inserts the player after the short description and add-to-cart area.</td></tr></tbody></table><h2 id="shortcodes-manual-placement" tabindex="-1">Shortcodes (Manual Placement) <a class="header-anchor" href="#shortcodes-manual-placement" aria-label="Permalink to &quot;Shortcodes (Manual Placement)&quot;">​</a></h2><p>If you need to place a video in a custom location (like within the product description or a page builder layout), you can use our <a href="/tubebay/features/shortcodes.html">Shortcode system</a>.</p><h2 id="custom-hooks" tabindex="-1">Custom Hooks <a class="header-anchor" href="#custom-hooks" aria-label="Permalink to &quot;Custom Hooks&quot;">​</a></h2><p>Developers can use the <code>tubebay_video_player</code> hook to render the player manually within their own theme templates.</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;?</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">php</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> echo</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> do_shortcode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;[tubebay_video]&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">); </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?&gt;</span></span></code></pre></div><h2 id="css-customization" tabindex="-1">CSS Customization <a class="header-anchor" href="#css-customization" aria-label="Permalink to &quot;CSS Customization&quot;">​</a></h2><p>Each player is wrapped in a dedicated container with the class <code>.tubebay-video-wrapper</code>. You can use this class to add custom margins, borders, or shadows via your theme&#39;s custom CSS.</p>',12)])])}const m=t(i,[["render",r]]);export{u as __pageData,m as default};
